import { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { deleteVehicle, getVehicles } from "../../api/vehicleApi";
import { getAuth } from "../../utils/auth";

export default function VehicleList() {
  const [vehicles, setVehicles] = useState([]);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const { role } = getAuth();
  const canManageVehicles = role === "admin" || role === "manager";

  const load = async () => {
    try {
      setLoading(true);
      const res = await getVehicles();
      setVehicles(res.data || []);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load vehicles");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const bookNow = (vehicleId, status) => {
    if (status !== "available") {
      alert("This vehicle is not available for booking.");
      return;
    }

    const token = localStorage.getItem("token");
    if (!token) {
      alert("Please login to book an appointment.");
      navigate("/login");
      return;
    }

    navigate("/book-appointment", { state: { vehicleId } });
  };

  const onDelete = async (id) => {
    if (!canManageVehicles) return alert("Access denied");
    if (!window.confirm("Delete this vehicle?")) return;

    try {
      await deleteVehicle(id);
      setVehicles((prev) => prev.filter((v) => v._id !== id));
      alert("Vehicle deleted");
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  const availabilityLabel = (status) => {
    if (status === "available") return "Available";
    if (status === "reserved") return "Reserved";
    if (status === "sold") return "Sold";
    return status;
  };

  const badgeStyle = (status) => {
    const base = {
      display: "inline-block",
      padding: "4px 10px",
      borderRadius: 999,
      fontSize: 12,
      fontWeight: 600,
      border: "1px solid #ccc",
      marginLeft: 8,
    };

    if (status === "available") return { ...base, borderColor: "#16a34a", color: "#16a34a" };
    if (status === "reserved") return { ...base, borderColor: "#f59e0b", color: "#f59e0b" };
    if (status === "sold") return { ...base, borderColor: "#ef4444", color: "#ef4444" };
    return base;
  };

  return (
    <div style={{ padding: 20 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <h2 style={{ margin: 0 }}>Vehicles</h2>
        <button onClick={load} disabled={loading} style={{ padding: "8px 12px" }}>
          {loading ? "Loading..." : "Refresh"}
        </button>
      </div>

      {canManageVehicles && (
        <div style={{ marginTop: 12 }}>
          <Link to="/vehicles/add">
            <button style={{ padding: "10px" }}>+ Add New Vehicle</button>
          </Link>
        </div>
      )}

      {vehicles.length === 0 && !loading && <p style={{ marginTop: 14 }}>No vehicles found.</p>}

      {vehicles.map((v) => (
        <div
          key={v._id}
          style={{
            border: "1px solid #ccc",
            margin: "12px 0",
            padding: "14px",
            borderRadius: 10,
          }}
        >
          <p style={{ margin: 0 }}>
            <strong>{v.brand} ({v.type})</strong>
            <span style={badgeStyle(v.status)}>{availabilityLabel(v.status)}</span>
          </p>

          <p style={{ margin: "8px 0" }}>Year: {v.year}</p>
          <p style={{ margin: "8px 0" }}>Price: Rs. {Number(v.price || 0).toLocaleString()}</p>

          <p style={{ margin: "8px 0" }}>
            Vehicle No: <b>{v.vehicleNumber || "-"}</b>
          </p>

          {v.details && (
            <p style={{ margin: "8px 0", opacity: 0.9 }}>
              Details: {v.details}
            </p>
          )}

          <div style={{ display: "flex", gap: 10, marginTop: 10, flexWrap: "wrap" }}>
            <button
              onClick={() => bookNow(v._id, v.status)}
              disabled={v.status !== "available"}
              style={{
                padding: "8px 12px",
                cursor: v.status === "available" ? "pointer" : "not-allowed",
                opacity: v.status === "available" ? 1 : 0.6,
              }}
            >
              Book Appointment
            </button>

            {canManageVehicles && (
              <>
                <button
                  onClick={() => navigate(`/vehicles/edit/${v._id}`)}
                  style={{ padding: "8px 12px" }}
                >
                  Edit
                </button>

                <button
                  onClick={() => onDelete(v._id)}
                  style={{ padding: "8px 12px" }}
                >
                  Delete
                </button>
              </>
            )}
          </div>
        </div>
      ))}
    </div>
  );
}
